const employees = ['Alice Johnson','Bob Smith','Carol White','David Lee','Eva Martinez','Frank Brown','Grace Kim','Henry Patel','Isabella Chen','James Williams'];
const issueTypes = ['VPN Not Connecting','Blue Screen of Death','Printer Offline','Email Not Syncing','Software License Expired','Wi-Fi Dropping','Laptop Won't Boot','Password Reset','Monitor Flickering','Slow Computer','Application Crash','Data Loss Warning'];
const severities = ['Critical','High','Medium','Low'];
const departments = ['Engineering','Marketing','Finance','HR','Sales','Operations','Legal'];
const tickets = [];
const now = new Date();
for (let i = 1; i <= 12; i++) {
  const issueType = issueTypes[Math.floor(Math.random() * issueTypes.length)];
  const employee = employees[Math.floor(Math.random() * employees.length)];
  const department = departments[Math.floor(Math.random() * departments.length)];
  const severityWeights = [1, 2, 4, 3];
  const totalWeight = severityWeights.reduce((a, b) => a + b, 0);
  let rand = Math.floor(Math.random() * totalWeight);
  let severityIdx = 0;
  for (let w = 0; w < severityWeights.length; w++) { rand -= severityWeights[w]; if (rand < 0) { severityIdx = w; break; } }
  const severity = severities[severityIdx];
  const minsAgo = Math.floor(Math.random() * 480);
  const submissionTime = new Date(now.getTime() - minsAgo * 60000).toISOString();
  tickets.push({ ticket_id: 'TKT-' + String(1000 + i).padStart(4, '0'), employee_name: employee, issue_type: issueType, severity: severity, department: department, submission_time: submissionTime });
}
return tickets.map(t => ({ json: t }));

const item = $input.item.json;
const networkIssues = ['VPN Not Connecting','Wi-Fi Dropping','Email Not Syncing'];
const hardwareIssues = ['Printer Offline','Laptop Won't Boot','Monitor Flickering','Blue Screen of Death'];
let team = 'Software Team';
if (networkIssues.includes(item.issue_type)) team = 'Network Team';
else if (hardwareIssues.includes(item.issue_type)) team = 'Hardware Team';
const slaMap = { Critical: { level: 'P1 - Critical', response_hours: 1, resolution_hours: 4 }, High: { level: 'P2 - High', response_hours: 4, resolution_hours: 8 }, Medium: { level: 'P3 - Medium', response_hours: 8, resolution_hours: 24 }, Low: { level: 'P4 - Low', response_hours: 24, resolution_hours: 72 } };
const sla = slaMap[item.severity] || slaMap['Low'];
const submittedAt = new Date(item.submission_time);
const responseDeadline = new Date(submittedAt.getTime() + sla.response_hours * 3600000).toISOString();
const resolutionDeadline = new Date(submittedAt.getTime() + sla.resolution_hours * 3600000).toISOString();
const isCritical = item.severity === 'Critical';
return { json: { ...item, assigned_team: team, sla_level: sla.level, response_deadline: responseDeadline, resolution_deadline: resolutionDeadline, response_hours_target: sla.response_hours, resolution_hours_target: sla.resolution_hours, is_critical: isCritical, status: isCritical ? 'ESCALATED' : 'OPEN', flagged: isCritical ? 'CRITICAL - IMMEDIATE ACTION' : null } };

const tickets = $input.all().map(i => i.json);
const total = tickets.length;
const open = tickets.filter(t => t.status === 'OPEN').length;
const escalated = tickets.filter(t => t.status === 'ESCALATED').length;
const critical = tickets.filter(t => t.severity === 'Critical').length;
const high = tickets.filter(t => t.severity === 'High').length;
const medium = tickets.filter(t => t.severity === 'Medium').length;
const low = tickets.filter(t => t.severity === 'Low').length;
const byTeam = { network: tickets.filter(t => t.queue === 'network').length, software: tickets.filter(t => t.queue === 'software').length, hardware: tickets.filter(t => t.queue === 'hardware').length };
const avgResponseTarget = Math.round(tickets.reduce((sum, t) => sum + (t.response_hours_target || 0), 0) / total * 10) / 10;
const avgResolutionTarget = Math.round(tickets.reduce((sum, t) => sum + (t.resolution_hours_target || 0), 0) / total * 10) / 10;
const criticalTicketIds = tickets.filter(t => t.is_critical).map(t => t.ticket_id).join(', ') || 'None';
return [{ json: { generated_at: new Date().toISOString(), summary: { total_tickets: total, open_tickets: open, escalated_tickets: escalated, critical_issues: critical, high_issues: high, medium_issues: medium, low_issues: low }, team_distribution: { network_team: byTeam.network, software_team: byTeam.software, hardware_team: byTeam.hardware }, sla_targets: { avg_response_target_hours: avgResponseTarget, avg_resolution_target_hours: avgResolutionTarget }, critical_ticket_ids: criticalTicketIds, all_tickets: tickets } }];
